// Build LinkedIn outreach context
const prospect = $input.first().json;
const f = prospect.fields || {};

// Determine connection message angle
let angle = 'general';
let hook = '';

if (f['Has Communication Pain']) {
  angle = 'missed_calls';
  hook = 'noticed you might be losing calls after hours';
} else if (f['Google Rating'] && f['Google Rating'] < 4.2) {
  angle = 'reviews';
  hook = 'saw an opportunity to boost your reviews';
} else {
  angle = 'growth';
  hook = 'helping HVAC owners in ' + (f['City'] || 'your area') + ' capture more leads';
}

return {
  json: {
    prospectId: prospect.id,
    companyName: f['Company Name'] || '',
    contactName: f['Contact Name'] || f['Owner Name'] || '',
    linkedInUrl: f['LinkedIn URL'] || '',
    city: f['City'] || '',
    state: f['State'] || '',
    rating: f['Google Rating'] || 0,
    reviewCount: f['Review Count'] || 0,
    painPoints: f['Pain Points'] || '',
    angle: angle,
    hook: hook
  }
};

