const response = $input.first().json.message?.content || $input.first().json.text || '{}';
let messages;

try {
  messages = JSON.parse(response);
} catch (e) {
  const match = response.match(/\{[\s\S]*\}/);
  messages = match ? JSON.parse(match[0]) : {};
}

const context = $('Build LinkedIn Context').first().json;

return {
  json: {
    ...context,
    connectionRequest: messages.connectionRequest || '',
    followUp1: messages.followUp1 || '',
    followUp2: messages.followUp2 || '',
    followUp3: messages.followUp3 || ''
  }
};

// Create task list for manual LinkedIn actions
const messagesReady = $('Save to Airtable').all();
const followUps = $('Get Follow-Up 1 Due').all();

const dailyTasks = [];

// New connection requests
messagesReady.forEach(p => {
  dailyTasks.push({
    type: 'connection_request',
    company: p.json.fields?.['Company Name'],
    linkedInUrl: p.json.fields?.['LinkedIn URL'],
    message: p.json.fields?.['LinkedIn Connection Msg'],
    priority: 'high'
  });
});

// Follow-ups
followUps.forEach(p => {
  dailyTasks.push({
    type: 'follow_up',
    company: p.json.fields?.['Company Name'],
    linkedInUrl: p.json.fields?.['LinkedIn URL'],
    message: p.json.fields?.['LinkedIn Follow-Up 1'],
    priority: 'medium'
  });
});

return {
  json: {
    date: new Date().toLocaleDateString(),
    totalTasks: dailyTasks.length,
    connectionRequests: dailyTasks.filter(t => t.type === 'connection_request').length,
    followUps: dailyTasks.filter(t => t.type === 'follow_up').length,
    tasks: dailyTasks
  }
};

